const EventEmitter = require('events');

// Create an instance of EventEmitter
const eventEmitter = new EventEmitter();

// Define a listener for the 'message' event
eventEmitter.on('message', (data) => {
  console.log('Message received:', data);
});

// Emit the 'message' event
eventEmitter.emit('message', 'Hello, event-driven world!');

const redis = require('redis');

// Create subscriber and publisher clients
const subscriber = redis.createClient();
const publisher = redis.createClient();

// Subscribe to the 'notifications' channel
subscriber.subscribe('notifications');

subscriber.on('message', (channel, message) => {
  console.log(`Received message from ${channel}: ${message}`);
});

// Publish a message every 3 seconds
setInterval(() => {
  publisher.publish('notifications', 'New notification at ' + new Date());
}, 3000);

function firstElement(array: any[]): any {
  return array[0];
}

function firstElement<T>(array: T[]): T {
  return array[0];
}

const numbers = [1, 2, 3];
const firstNumber = firstElement(numbers); // TypeScript infers firstNumber as number

const strings = ['a', 'b', 'c'];
const firstString = firstElement(strings); // TypeScript infers firstString as string

class Stack<T> {
  private items: T[] = [];

  push(item: T) {
    this.items.push(item);
  }

  pop(): T | undefined {
    return this.items.pop();
  }

  peek(): T | undefined {
    return this.items[this.items.length - 1];
  }
}

const numberStack = new Stack<number>();
numberStack.push(10);
numberStack.push(20);
console.log(numberStack.pop()); // 20

interface HasId {
  id: number;
}

function getById<T extends HasId>(items: T[], id: number): T | undefined {
  return items.find(item => item.id === id);
}

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' }
];

const user = getById(users, 2);
console.log(user); // { id: 2, name: 'Bob' }

function greet(name) {
  if (name !== null && name !== undefined) {
    console.log(`Hello, ${name}!`);
  } else {
    console.log('Hello, guest!');
  }
}

greet('Alice'); // Hello, Alice!
greet(null);    // Hello, guest!

function greet(name: string | null) {
  if (name === null) {
    console.log('Hello, guest!');
  } else {
    // name is guaranteed to be a string here
    console.log(`Hello, ${name}!`);
  }
}

greet('Alice'); // Hello, Alice!
greet(null);    // Hello, guest!

