from pydantic import BaseModel, validator, ValidationError

class UserModel(BaseModel):
    name: str
    age: int
    email: str

    @validator('age')
    def age_must_be_positive(cls, v):
        if v <= 0:
            raise ValueError('Age must be a positive integer')
        return v

    @validator('email')
    def email_must_contain_at_sign(cls, v):
        if '@' not in v:
            raise ValueError('Invalid email address')
        return v

try:
    user = UserModel(name='Alice', age=-1, email='aliceexample.com')
except ValidationError as e:
    print(e.json())

try:
    user = UserModel(name='Bob', age=0, email='bobexample.com')
except ValidationError as e:
    for error in e.errors():
        print(f"Error in field '{error['loc'][0]}': {error['msg']}")

import attr

@attr.s
class Product:
    name = attr.ib(type=str)
    price = attr.ib(type=float)

    @price.validator
    def check_price(self, attribute, value):
        if value < 0:
            raise ValueError('Price must be non-negative')

# Usage
try:
    p = Product(name='Laptop', price=-1200)
except ValueError as e:
    print(e)

def validate_int(value):
    try:
        ivalue = int(value)
        if ivalue <= 0:
            raise ValueError('Value must be positive')
        return ivalue
    except ValueError as e:
        raise ValueError(f'Invalid input: {e}')

# Usage
try:
    age = validate_int('25')
    print(f'Age is {age}')
    age = validate_int('-5')
except ValueError as e:
    print(e)

